سأقوم بتحديث التطبيق لإضافة لوحة خيارات تتيح للمستخدم تحديد الخدمات المطلوبة (تنسيق، تعليقات، معالجة أخطاء، ترقيم، وتوافقية النواة) وتعديل منطق الذكاء الاصطناعي لتنفيذ هذه التعليمات بناءً على اختيارات المستخدم.

# Changes:

1.  **`types.ts`**: إضافة واجهة `ProcessingOptions` لتعريف الخيارات الجديدة.
2.  **`services/geminiService.ts`**: تحديث دالة التحويل `convertVBACode` لاستقبال الخيارات وبناء "System Instruction" ديناميكي للذكاء الاصطناعي بناءً على ما تم تحديده.
3.  **`App.tsx`**: إضافة واجهة مستخدم (UI) عبارة عن مربعات اختيار (Checkboxes) أو أزرار تبديل للتحكم في الخيارات قبل المعالجة.

# Updated files:

## types.ts

Add `ProcessingOptions` interface.

```typescript
export enum AnalysisStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING',
  CONVERTING = 'CONVERTING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface LogEntry {
  id: string;
  message: string;
  type: 'info' | 'success' | 'warning' | 'error';
  timestamp: Date;
}

export interface CompatibilityReport {
  isCompatible: boolean;
  issues: string[];
  bit32Only: boolean;
  bit64Only: boolean;
}

export interface ProcessingOptions {
  compatibility: boolean;  // تحويل 32/64 بت
  formatting: boolean;     // تنسيق الكود
  comments: boolean;       // تعليقات عربي/إنجليزي
  errorHandling: boolean;  // صائد الأخطاء
  lineNumbers: boolean;    // ترقيم الأسطر
}
```

## services/geminiService.ts

Update service to accept options and build dynamic prompts.

```typescript
import { GoogleGenAI } from "@google/genai";
import { ProcessingOptions } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const convertVBACode = async (code: string, options: ProcessingOptions): Promise<string> => {
  if (!code.trim()) return "";

  try {
    const model = 'gemini-2.5-flash';

    // بناء التعليمات ديناميكياً بناءً على اختيارات المستخدم
    let instructionParts = [
      `You are an expert Visual Basic (VBA/VB6) developer known as "VBA Code Doctor".`,
      `Your task is to rewrite the user's code applying ONLY the enabled rules below.`,
      `Output raw VBA code only.`
    ];

    if (options.compatibility) {
      instructionParts.push(`
      [ENABLED] COMPATIBILITY RULE (32-bit & 64-bit):
      - You MUST wrap every API 'Declare' statement in an #If VBA7 block.
      - #If VBA7 Then: Use 'Declare PtrSafe' and 'LongPtr' for handles/pointers.
      - #Else: Use 'Declare' (no PtrSafe) and 'Long' for handles/pointers.
      - Ensure the logic works on both architectures.
      `);
    }

    if (options.formatting) {
      instructionParts.push(`
      [ENABLED] FORMATTING RULE:
      - Indent code perfectly using 4 spaces.
      - Add blank lines between procedures.
      - Fix casing of keywords (e.g., 'sub' -> 'Sub', 'dim' -> 'Dim').
      `);
    }

    if (options.comments) {
      instructionParts.push(`
      [ENABLED] COMMENTS RULE:
      - Add comprehensive comments to explain complex logic.
      - Comments MUST be in BOTH Arabic and English.
      - Example: ' حفظ الملف -- Save the file
      `);
    }

    if (options.errorHandling) {
      instructionParts.push(`
      [ENABLED] ERROR HANDLING RULE:
      - Wrap every Sub and Function with a robust error handler.
      - Pattern:
        On Error GoTo ErrorHandler
        ' ... code ...
        Exit Sub
        ErrorHandler:
        MsgBox "Error " & Err.Number & ": " & Err.Description, vbCritical, "Error"
        Resume Next ' Or Exit, depending on safety
      `);
    }

    if (options.lineNumbers) {
      instructionParts.push(`
      [ENABLED] LINE NUMBERS RULE:
      - Add standard VBA line numbers (10, 20, 30...) to every executable line of code.
      - This is for use with the 'Erl' function.
      - Do not number Dim statements, comments, or labels.
      `);
    }

    const systemInstruction = instructionParts.join("\n");

    const response = await ai.models.generateContent({
      model: model,
      contents: [
        {
          role: 'user',
          parts: [{ text: `Apply the enabled rules to this code:\n\n${code}` }]
        }
      ],
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.2, 
      }
    });

    return response.text?.trim() || "";
  } catch (error) {
    console.error("Gemini Conversion Error:", error);
    throw new Error("حدث خطأ أثناء الاتصال بخدمة الذكاء الاصطناعي");
  }
};

export const analyzeCodeIssues = async (code: string): Promise<string[]> => {
    if (!code.trim()) return [];

    try {
        const model = 'gemini-2.5-flash';
        const response = await ai.models.generateContent({
            model: model,
            contents: `Analyze this VBA code for 64-bit compatibility. 
            Check if it lacks "PtrSafe" or uses "Long" for pointers/handles which would crash on 64-bit.
            Return a JSON string array of short Arabic warning messages. If safe, return []. Code: \n${code}`,
            config: {
                responseMimeType: "application/json"
            }
        });

        const text = response.text || "[]";
        return JSON.parse(text);
    } catch (e) {
        return ["تعذر تحليل الكود بدقة حالياً."];
    }
}
```

## App.tsx

Add settings panel with checkboxes.

```tsx
import React, { useState } from 'react';
import { Cpu, Zap, RotateCcw, ShieldCheck, Settings2, FileCode, MessageSquare, Bug, Hash, AlignLeft } from 'lucide-react';
import CodeEditor from './components/CodeEditor';
import Terminal from './components/Terminal';
import { AnalysisStatus, LogEntry, ProcessingOptions } from './types';
import { convertVBACode, analyzeCodeIssues } from './services/geminiService';

export default function App() {
  const [inputCode, setInputCode] = useState<string>('');
  const [outputCode, setOutputCode] = useState<string>('');
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [logs, setLogs] = useState<LogEntry[]>([]);

  // Options State
  const [options, setOptions] = useState<ProcessingOptions>({
    compatibility: true,
    formatting: false,
    comments: false,
    errorHandling: false,
    lineNumbers: false
  });

  const addLog = (message: string, type: LogEntry['type'] = 'info') => {
    setLogs(prev => [...prev, {
      id: Math.random().toString(36).substr(2, 9),
      message,
      type,
      timestamp: new Date()
    }]);
  };

  const handleReset = () => {
    setInputCode('');
    setOutputCode('');
    setLogs([]);
    setStatus(AnalysisStatus.IDLE);
    addLog('System reset.', 'info');
  };

  const toggleOption = (key: keyof ProcessingOptions) => {
    setOptions(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleProcess = async () => {
    if (!inputCode.trim()) {
      addLog('Input is empty. Please provide VBA code.', 'warning');
      return;
    }

    // Phase 1: Analyze
    setStatus(AnalysisStatus.ANALYZING);
    addLog('Initializing code analysis module...', 'info');

    // Quick heuristic check before AI
    if (options.compatibility) {
        const hasPtrSafe = inputCode.toLowerCase().includes('ptrsafe');
        if (!hasPtrSafe) {
            addLog('Detected potential 32-bit legacy Declarations (Missing PtrSafe).', 'warning');
        }
    }

    try {
        // AI Analysis (Only runs basic checks, separate from the main conversion options)
        const issues = await analyzeCodeIssues(inputCode);
        if (issues.length > 0) {
            issues.forEach(issue => addLog(`Issue identified: ${issue}`, 'warning'));
        } else {
             addLog('Initial structure analysis completed.', 'success');
        }

        // Phase 2: Convert
        setStatus(AnalysisStatus.CONVERTING);
        addLog('Applying selected processing rules...', 'info');

        const converted = await convertVBACode(inputCode, options);

        setOutputCode(converted);
        setStatus(AnalysisStatus.COMPLETED);
        addLog('Processing completed successfully.', 'success');

    } catch (error: any) {
        setStatus(AnalysisStatus.ERROR);
        addLog(error.message || 'An unknown error occurred.', 'error');
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex flex-col overflow-hidden">
      {/* Navbar */}
      <header className="h-16 border-b border-slate-800 bg-slate-900/80 backdrop-blur-md flex items-center justify-between px-6 z-10 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-lg bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Cpu className="text-white" size={24} />
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">VBA Code Doctor</h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-semibold">AI Powered Architecture Fixer</p>
          </div>
        </div>

        <div className="hidden md:flex items-center gap-4 text-sm text-slate-400">
           <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full border transition-colors ${options.compatibility ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-200' : 'bg-slate-800/50 border-slate-700'}`}>
             <ShieldCheck size={14} className={options.compatibility ? "text-indigo-400" : "text-slate-500"}/>
             <span>Engine: {options.compatibility ? 'Active' : 'Standard'}</span>
           </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 relative flex flex-col p-4 md:p-6 gap-4 overflow-hidden">

        {/* Settings Panel */}
        <div className="bg-slate-900/50 border border-slate-800 rounded-lg p-3">
          <div className="flex flex-col md:flex-row items-center justify-between gap-4">

             {/* Options Grid */}
             <div className="flex flex-wrap items-center gap-3 w-full md:w-auto justify-center md:justify-start">
                <div className="flex items-center gap-2 text-slate-400 text-sm font-semibold ml-2 border-l border-slate-700 pl-3">
                    <Settings2 size={16} />
                    <span>خيارات المعالجة:</span>
                </div>

                <button 
                  onClick={() => toggleOption('compatibility')}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm border transition-all ${options.compatibility ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-900/50' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750'}`}
                >
                  <ShieldCheck size={14} />
                  <span>توافق 32/64</span>
                </button>

                <button 
                  onClick={() => toggleOption('formatting')}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm border transition-all ${options.formatting ? 'bg-emerald-600 border-emerald-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750'}`}
                >
                  <AlignLeft size={14} />
                  <span>تنسيق</span>
                </button>

                <button 
                  onClick={() => toggleOption('comments')}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm border transition-all ${options.comments ? 'bg-blue-600 border-blue-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750'}`}
                >
                  <MessageSquare size={14} />
                  <span>تعليقات (ع/en)</span>
                </button>

                <button 
                  onClick={() => toggleOption('errorHandling')}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm border transition-all ${options.errorHandling ? 'bg-amber-600 border-amber-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750'}`}
                >
                  <Bug size={14} />
                  <span>صائد الأخطاء</span>
                </button>

                <button 
                  onClick={() => toggleOption('lineNumbers')}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm border transition-all ${options.lineNumbers ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-slate-400 hover:bg-slate-750'}`}
                >
                  <Hash size={14} />
                  <span>ترقيم الأسطر</span>
                </button>
             </div>

             {/* Action Buttons */}
             <div className="flex gap-2 w-full md:w-auto justify-end">
                <button 
                  onClick={handleReset}
                  className="px-3 py-1.5 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-md transition-all flex items-center gap-2 border border-slate-700 font-medium text-xs md:text-sm"
                >
                    <RotateCcw size={14} />
                    <span>تفريغ</span>
                </button>
                <button 
                  onClick={handleProcess}
                  disabled={status === AnalysisStatus.ANALYZING || status === AnalysisStatus.CONVERTING}
                  className={`px-4 py-1.5 rounded-md transition-all flex items-center gap-2 font-bold text-xs md:text-sm shadow-lg whitespace-nowrap
                    ${status === AnalysisStatus.ANALYZING || status === AnalysisStatus.CONVERTING 
                      ? 'bg-indigo-900/50 text-indigo-300 cursor-not-allowed border border-indigo-800' 
                      : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-500/25 border border-indigo-500'}`}
                >
                    <Zap size={14} className={status === AnalysisStatus.CONVERTING ? "fill-current" : ""} />
                    <span>تشغيل المعالج</span>
                </button>
            </div>
          </div>
        </div>

        {/* Editors Grid */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 flex-1 min-h-0">
            <CodeEditor 
                title="الكود الأصلي (VBA)" 
                code={inputCode} 
                onChange={setInputCode}
                placeholder="ألصق كود VBA هنا... مثال: Private Declare Function..."
                borderColor={inputCode && options.compatibility && !inputCode.toLowerCase().includes('ptrsafe') ? 'border-amber-500/30' : 'border-slate-700'}
            />
            <CodeEditor 
                title="الكود الناتج" 
                code={outputCode} 
                readOnly
                placeholder="سيظهر الكود الناتج هنا بعد المعالجة..."
                borderColor={outputCode ? 'border-emerald-500/30' : 'border-slate-700'}
            />
        </div>
      </main>

      {/* Terminal/Footer */}
      <footer className="shrink-0 z-10">
        <Terminal logs={logs} status={status} />
      </footer>
    </div>
  );
}
```
